const trigger = $('Execute Workflow Trigger').first().json;
const existingFiles = $json.files || [];
const sessionId = `${trigger.project_id || 'proj'}-${(trigger.task || {}).task_id || 'default'}`;
return [{ json: {
  task: trigger.task || {},
  project_goal: trigger.project_goal || '',
  previous_feedback: trigger.previous_feedback || '',
  existing_files: existingFiles,
  session_id: sessionId,
  project_id: trigger.project_id
} }];

const qr = $json.quality_review || {};
const sr = $json.security_review || {};
// Detect reviewer parse failures — if raw_output exists, review JSON was unparseable
const securityParseFailed = !!sr.raw_output;
const qualityParseFailed = !!qr.raw_output;
// If both reviews parsed OK, apply normal gate logic
const score = qr.quality_score || 0;
const jobComplete = qr.job_complete === true;
const criticalCount = (sr.critical_issues || []).length;
let shouldStop;
if (securityParseFailed && qualityParseFailed) {
  // Both reviews failed to parse — accept the code as-is rather than looping with empty feedback
  shouldStop = true;
} else {
  shouldStop = jobComplete || (score >= 8 && criticalCount === 0);
}
const feedback = [
  ...(sr.critical_issues || []).map(i => `SECURITY CRITICAL: ${i.issue} → ${i.fix}`),
  ...(sr.high_priority || []).map(i => `SECURITY HIGH: ${i.issue} → ${i.fix}`),
  ...(qr.areas_for_improvement || []).map(a => `QUALITY: ${a.area} → ${a.fix}`),
  ...(securityParseFailed ? ['SECURITY REVIEW: Parser failed — review output manually'] : []),
  ...(qualityParseFailed ? ['QUALITY REVIEW: Parser failed — review output manually'] : [])
].join('\n');
return [{ json: {
  should_stop: shouldStop,
  files: $json.files || [],
  security_review: sr,
  quality_review: qr,
  fixed: !shouldStop,
  feedback_for_next: feedback
} }];

const trigger = $('Execute Workflow Trigger').first().json;
const diskFiles = $('Read Existing Files').first().json.files || [];
const generatedFiles = $json.files || [];
const fileMap = new Map();
diskFiles.forEach(f => fileMap.set(f.path, f));
generatedFiles.forEach(f => fileMap.set(f.path, f));
const mergedFiles = Array.from(fileMap.values());
const sessionId = `${trigger.project_id || 'proj'}-${(trigger.task || {}).task_id || 'default'}`;
return [{ json: {
  task: trigger.task || {},
  project_goal: trigger.project_goal || '',
  previous_feedback: $json.feedback_for_next,
  existing_files: mergedFiles,
  session_id: sessionId,
  project_id: trigger.project_id
} }];

const qr = $json.quality_review || {};
const sr = $json.security_review || {};
const securityParseFailed = !!sr.raw_output;
const qualityParseFailed = !!qr.raw_output;
const score = qr.quality_score || 0;
const jobComplete = qr.job_complete === true;
const criticalCount = (sr.critical_issues || []).length;
let shouldStop;
if (securityParseFailed && qualityParseFailed) {
  shouldStop = true;
} else {
  shouldStop = jobComplete || (score >= 8 && criticalCount === 0);
}
const feedback = [
  ...(sr.critical_issues || []).map(i => `SECURITY CRITICAL: ${i.issue} → ${i.fix}`),
  ...(sr.high_priority || []).map(i => `SECURITY HIGH: ${i.issue} → ${i.fix}`),
  ...(qr.areas_for_improvement || []).map(a => `QUALITY: ${a.area} → ${a.fix}`),
  ...(securityParseFailed ? ['SECURITY REVIEW: Parser failed — review output manually'] : []),
  ...(qualityParseFailed ? ['QUALITY REVIEW: Parser failed — review output manually'] : [])
].join('\n');
return [{ json: {
