} }];

const trigger = $('Execute Workflow Trigger').first().json;
const diskFiles = $('Read Existing Files').first().json.files || [];
const generatedFiles = $json.files || [];
const fileMap = new Map();
diskFiles.forEach(f => fileMap.set(f.path, f));
generatedFiles.forEach(f => fileMap.set(f.path, f));
const mergedFiles = Array.from(fileMap.values());
const sessionId = `${trigger.project_id || 'proj'}-${(trigger.task || {}).task_id || 'default'}`;
return [{ json: {
  task: trigger.task || {},
  project_goal: trigger.project_goal || '',
  previous_feedback: $json.feedback_for_next,
  existing_files: mergedFiles,
  session_id: sessionId,
  project_id: trigger.project_id
} }];

const files = $json.files || [];
const projectId = $('Execute Workflow Trigger').first().json.project_id;
// For P3 path, reviews aren't available on $json — pull last known from Quality Gate 2 if available
let sr = $json.security_review || null;
let qr = $json.quality_review || null;
let fixed = $json.fixed || false;
try {
  const gate2 = $('Quality Gate 2').first().json;
  if (!sr) sr = gate2.security_review || null;
  if (!qr) qr = gate2.quality_review || null;
  fixed = true;
} catch(e) { /* P1/P2 path — reviews already on $json */ }
return [{ json: {
  project_id: projectId,
  files: files,
  security_review: sr,
  quality_review: qr,
  fixed: fixed
} }];

const task = $('Build Input P1').first().json.task;
const writeResult = $json;
return [{ json: {
  task_id: task.task_id || 'unknown',
  description: task.description || '',
  files_written: (writeResult.files_written || []).map(f => f.path),
  security_review: $json.security_review,
  quality_review: $json.quality_review,
  fixed: $json.fixed || false
} }];
